<?php
namespace App\Domain\Combat;use App\Domain\Combat\Data\CombatMitigationConfig;use App\Models\CombatBalanceSetting;use App\Models\User;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class CombatBalanceConfigurationService{public function update(User $admin,array $data){return DB::transaction(function()use($admin,$data){$setting=CombatBalanceSetting::whereKey(1)->lockForUpdate()->firstOrFail();if((int)$data['version']!==(int)$setting->version)throw new InvalidArgumentException('La configuración fue modificada por otro administrador.');$config=new CombatMitigationConfig((int)$data['defense_reduction_cap_basis_points'],(int)$data['absorb_damage_cap_basis_points'],(int)$data['total_mitigation_cap_basis_points'],(int)$data['minimum_damage']);$setting->fill($config->toArray());$setting->version=(int)$setting->version+1;$setting->updated_by=$admin->id;$setting->save();return$setting;},3);}}
